export default function OnboardingScreen() {
  const router = useRouter();
  const c = useTheme();

  // Branding the device when they leave the onboarding flow
  const handleGetStarted = () => {
    router.push('/(auth)/register');
  };

  const handleSignIn = () => {
    router.push('/(auth)/login');
  };

  return (
    <SafeAreaView style={[styles.container, { backgroundColor: c.ui.background }]}>
      
      {/* 1. Illustration Container */}
      <View style={styles.imageContainer}>
        <OnboardingIllustration />
      </View>

      {/* 2. Text Content */}
      <View style={styles.contentContainer}>
        <Text style={[styles.title, { color: c.text.primary }]}>
          Welcome to LexiAssist
        </Text>
        <Text style={[styles.subtitle, { color: c.text.muted }]}>
          Learn faster, Learn Smarter
        </Text>
      </View>

      {/* 3. Button Actions */}
      <View style={styles.actionContainer}>
        <TouchableOpacity
          style={[styles.primaryButton, { backgroundColor: c.brand.primary }]}
          activeOpacity={0.88}
          onPress={handleGetStarted}
        >
          <Text style={[styles.primaryButtonText, { color: c.text.inverse }]}>
            Get Started
          </Text>
        </TouchableOpacity>

        <TouchableOpacity
          style={[styles.secondaryButton, { borderColor: c.brand.primary }]}
          activeOpacity={0.88}
          onPress={handleSignIn}
        >
          <Text style={[styles.secondaryButtonText, { color: c.brand.primary }]}>
            Sign In
          </Text>
        </TouchableOpacity>
      </View>

    </SafeAreaView>
  );
}

